```typescript
import { Effect, pipe } from "effect";

const items: ReadonlyArray<Effect.Effect<number>> = [
  Effect.succeed(1),
  Effect.succeed(2),
  Effect.succeed(3),
  Effect.succeed(4),
];

interface Accum { readonly total: number; readonly partials: ReadonlyArray<number> }

export const scan: Effect.Effect<Accum> = Effect.reduce(
  items,
  { total: 0, partials: [] as ReadonlyArray<number> },
  (acc, eff) =>
    pipe(
      eff,
      Effect.map((n) => {
        const total = acc.total + n;
        return { total, partials: [...acc.partials, total] };
      }),
    ),
);
