Effect.reduce threads an accumulator through each step. Because each step returns an Effect, a failure in any element short-circuits the fold without iterating further, giving strict sequential semantics.

```typescript
import { Effect, Data } from "effect";

class Negative extends Data.TaggedError("Negative")<{ readonly value: number }> {}

const nums: ReadonlyArray<Effect.Effect<number, Negative>> = [
  Effect.succeed(1),
  Effect.succeed(2),
  Effect.succeed(3),
];

const step = (acc: number, eff: Effect.Effect<number, Negative>): Effect.Effect<number, Negative> =>
  Effect.flatMap(eff, (n) =>
    n < 0 ? Effect.fail(new Negative({ value: n })) : Effect.succeed(acc + n),
  );

export const sumPositives: Effect.Effect<number, Negative> = Effect.reduce(nums, 0, step);
```

