import { Effect } from "effect";

interface Accum<S, B> { readonly state: S; readonly out: ReadonlyArray<B> }

export const mapAccum = <A, B, S, E, R>(
  items: ReadonlyArray<A>,
  initial: S,
  step: (state: S, a: A) => Effect.Effect<readonly [S, B], E, R>,
): Effect.Effect<Accum<S, B>, E, R> =>
  Effect.reduce(
    items,
    { state: initial, out: [] as ReadonlyArray<B> } as Accum<S, B>,
    (acc, a) =>
      Effect.map(step(acc.state, a), ([s1, b]) => ({
        state: s1,
        out: [...acc.out, b],
      })),
  );

// example: cumulative index assignment
export const indexed: Effect.Effect<Accum<number, { readonly id: number; readonly name: string }>> =
  mapAccum(["a", "b", "c"], 0, (i, name) =>
    Effect.succeed([i + 1, { id: i + 1, name }] as const),
  );
```

mapAccum is a fold that also emits a per-element output. You return a tuple (newState, b) on each step; the final result is the last state plus the collected bs. In Effect it's expressed as Effect.reduce over an { state, out } accumulator.

