```typescript
import { Effect, Data } from "effect";

class StepFailed extends Data.TaggedError("StepFailed")<{ readonly reason: string }> {}

interface MapAccumResult<S, B> { readonly state: S; readonly outputs: ReadonlyArray<B> }

export const mapAccumEffect = <A, B, S, E, R>(
  inputs: ReadonlyArray<A>,
  initial: S,
  step: (s: S, a: A) => Effect.Effect<readonly [S, B], E, R>,
): Effect.Effect<MapAccumResult<S, B>, E, R> =>
  Effect.reduce(
    inputs,
    { state: initial, outputs: [] as ReadonlyArray<B> } as MapAccumResult<S, B>,
    (acc, a) =>
      Effect.map(step(acc.state, a), ([s1, b]) => ({
        state: s1,
        outputs: [...acc.outputs, b],
      })),
  );

export const balances: Effect.Effect<MapAccumResult<number, number>, StepFailed> =
  mapAccumEffect([100, -20, -30, 50], 0, (bal, delta) => {
    const next = bal + delta;
    return next < 0
      ? Effect.fail(new StepFailed({ reason: "overdraft" }))
      : Effect.succeed([next, next] as const);
  });
