import { Effect, Context, Data, Layer } from "effect";

class QueryError extends Data.TaggedError("QueryError")<{ readonly sql: string }> {}
class CacheMiss extends Data.TaggedError("CacheMiss")<{ readonly key: string }> {}

interface DB { readonly query: (sql: string) => Effect.Effect<string, QueryError> }
interface Cache { readonly get: (k: string) => Effect.Effect<number, CacheMiss> }

const DB = Context.GenericTag<DB>("app/DB");
const Cache = Context.GenericTag<Cache>("app/Cache");

interface DTO { readonly row: string; readonly hit: number }

export const combined: Effect.Effect<DTO, QueryError | CacheMiss, DB | Cache> = Effect.gen(function* () {
  const db = yield* DB;
  const cache = yield* Cache;
  return yield* Effect.zipWith(
    db.query("select 1"),
    cache.get("k"),
    (row, hit) => ({ row, hit }),
  );
});

export const Live = Layer.mergeAll(
  Layer.succeed(DB, { query: () => Effect.succeed("row") }),
  Layer.succeed(Cache, { get: () => Effect.succeed(42) }),
);
```

