import { Effect, Context, Data, Layer, pipe } from "effect";

class InvalidForm extends Data.TaggedError("InvalidForm")<{ readonly reason: string }> {}
class HashFailed extends Data.TaggedError("HashFailed")<{ readonly cause: string }> {}
class PersistFailed extends Data.TaggedError("PersistFailed")<{ readonly id: string }> {}

interface Form { readonly email: string; readonly password: string }
interface Hasher { readonly hash: (p: string) => Effect.Effect<string, HashFailed> }
interface Repo { readonly save: (email: string, hash: string) => Effect.Effect<string, PersistFailed> }

const Hasher = Context.GenericTag<Hasher>("app/Hasher");
const Repo = Context.GenericTag<Repo>("app/Repo");

const validate = (f: Form): Effect.Effect<Form, InvalidForm> =>
  f.email.includes("@") && f.password.length >= 8
    ? Effect.succeed(f)
    : Effect.fail(new InvalidForm({ reason: "bad input" }));

export const register = (form: Form) =>
  pipe(
    Effect.Do,
    Effect.bind("hasher", () => Hasher),
    Effect.bind("repo", () => Repo),
    Effect.bind("valid", () => validate(form)),
    Effect.bind("hash", ({ hasher, valid }) => hasher.hash(valid.password)),
    Effect.bind("id", ({ repo, valid, hash }) => repo.save(valid.email, hash)),
    Effect.map(({ id }) => ({ userId: id })),
  );

export const Live = Layer.mergeAll(
  Layer.succeed(Hasher, { hash: (p) => Effect.succeed(`h:${p}`) }),
  Layer.succeed(Repo, { save: () => Effect.succeed("user_1") }),
);
