import { Effect, Data } from "effect";

class RefreshFailed extends Data.TaggedError("RefreshFailed")<{ readonly reason: string }> {}

interface Token { readonly value: string; readonly expiresAt: number }

const refresh = (t: Token): Effect.Effect<Token, RefreshFailed> =>
  t.value.length === 0
    ? Effect.fail(new RefreshFailed({ reason: "empty" }))
    : Effect.succeed({ value: `${t.value}-new`, expiresAt: Date.now() + 60_000 });

export const ensureFresh = (t: Token, now: number): Effect.Effect<Token, RefreshFailed> =>
  Effect.if(now >= t.expiresAt, {
    onTrue: () => refresh(t),
    onFalse: () => Effect.succeed(t),
  });
