import { Effect, Context, Layer } from "effect";

interface Buffer {
  readonly append: (item: string) => Effect.Effect<void>;
  readonly size: () => Effect.Effect<number>;
  readonly flush: () => Effect.Effect<void>;
}
const Buffer = Context.GenericTag<Buffer>("app/Buffer");

const THRESHOLD = 10;

export const addItem = (item: string) =>
  Effect.gen(function* () {
    const buffer = yield* Buffer;
    yield* buffer.append(item);
    const size = yield* buffer.size();
    yield* Effect.when(buffer.flush(), () => size >= THRESHOLD);
  });

export const BufferLive = Layer.succeed(Buffer, {
  append: () => Effect.void,
  size: () => Effect.succeed(0),
  flush: () => Effect.void,
});
