import { Effect, TestClock, Duration, Fiber } from "effect";

const waitThenFinish: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep(Duration.seconds(5));
  return "done";
});

export const testProgram: Effect.Effect<string> = Effect.gen(function* () {
  const fiber = yield* Effect.fork(waitThenFinish);
  yield* TestClock.adjust(Duration.seconds(5));
  const result = yield* Fiber.join(fiber);
  return result;
});
