```typescript
import { Effect, TestClock, Duration, Schedule, Fiber, pipe } from "effect";

let attempts = 0;
const flaky: Effect.Effect<string, string> = Effect.suspend(() => {
  attempts += 1;
  return attempts < 3 ? Effect.fail("transient") : Effect.succeed("ok");
});

const retried = pipe(flaky, Effect.retry(Schedule.exponential(Duration.seconds(1))));

export const test: Effect.Effect<string, string> = Effect.gen(function* () {
  const fiber = yield* Effect.fork(retried);
  yield* TestClock.adjust(Duration.seconds(10));
  return yield* Fiber.join(fiber);
});
```

TestClock replaces the live Clock with a virtual one whose time only advances when you call TestClock.adjust or setTime. Any Effect.sleep, Schedule, or timeout suspends until virtual time catches up, so tests are deterministic and instant.

