import { Effect, TestClock, Duration, Fiber, pipe } from "effect";

const debounced = (value: string): Effect.Effect<string> =>
  pipe(Effect.succeed(value), Effect.delay(Duration.millis(500)));

export const test: Effect.Effect<string> = Effect.gen(function* () {
  const fiber = yield* Effect.fork(debounced("click"));
  // advance by less than the debounce: fiber still pending
  yield* TestClock.adjust(Duration.millis(200));
  // finish the debounce window
  yield* TestClock.adjust(Duration.millis(300));
  return yield* Fiber.join(fiber);
});
```

